public string FormatDate(DateTime date)
{
    return date.ToString("d", CultureInfo.CurrentCulture); // Compliant: Using standard format
}

public void DisplayTime(DateTime time)
{
    string formatted = time.ToString("T", CultureInfo.InvariantCulture); // Compliant
    Console.WriteLine(formatted);
}

